export function riskProgramProgram() {
  return <T extends RiskProgramPluginRequirements>(client: T) => {
    return {
      ...client,
      riskProgram: <RiskProgramPlugin>{
        accounts: {
          fundingState: addSelfFetchFunctions(client, getFundingStateCodec()),
          insuranceFund: addSelfFetchFunctions(client, getInsuranceFundCodec()),
          marketConfig: addSelfFetchFunctions(client, getMarketConfigCodec()),
          position: addSelfFetchFunctions(client, getPositionCodec()),
          userAccount: addSelfFetchFunctions(client, getUserAccountCodec()),
        },
        instructions: {
          createRiskMarket: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCreateRiskMarketInstruction({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          initializeInsuranceFund: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitializeInsuranceFundInstruction({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          initializeVault: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitializeVaultInstruction({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          deposit: (input) =>
            addSelfPlanAndSendFunctions(client, getDepositInstruction(input)),
          withdraw: (input) =>
            addSelfPlanAndSendFunctions(client, getWithdrawInstruction(input)),
          openPosition: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getOpenPositionInstruction(input),
            ),
          closePosition: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getClosePositionInstruction(input),
            ),
          addMargin: (input) =>
            addSelfPlanAndSendFunctions(client, getAddMarginInstruction(input)),
          removeMargin: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getRemoveMarginInstruction(input),
            ),
          settleFill: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSettleFillInstruction({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          settleFunding: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSettleFundingInstruction(input),
            ),
          updateFundingRate: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateFundingRateInstruction(input),
            ),
          liquidate: (input) =>
            addSelfPlanAndSendFunctions(client, getLiquidateInstruction(input)),
          coverBadDebt: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCoverBadDebtInstruction(input),
            ),
          depositInsurance: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getDepositInsuranceInstruction(input),
            ),
        },
      },
    };
  };
}

type MakeOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
